"use client";

import { useEffect, useState, useRef } from "react";
import gsap from "gsap";

export default function CustomScrollbar() {
  const [scrollProgress, setScrollProgress] = useState(0);
  const [isScrolling, setIsScrolling] = useState(false);
  const scrollTimeout = useRef(null);
  const thumbRef = useRef(null);

  useEffect(() => {
    const handleScroll = () => {
      const totalHeight = document.documentElement.scrollHeight - window.innerHeight;
      if (totalHeight <= 0) return;
      
      const progress = window.scrollY / totalHeight;
      setScrollProgress(progress);
      
      setIsScrolling(true);
      
      if (scrollTimeout.current) clearTimeout(scrollTimeout.current);
      scrollTimeout.current = setTimeout(() => {
        setIsScrolling(false);
      }, 150);
    };

    window.addEventListener("scroll", handleScroll);
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  // Update thumb color based on progress (Blue to Pink)
  const getThumbColor = () => {
    const r = Math.round(136 + (255 - 136) * scrollProgress);
    const g = Math.round(187 + (136 - 187) * scrollProgress);
    const b = Math.round(255 + (204 - 255) * scrollProgress);
    return `rgb(${r}, ${g}, ${b})`;
  };

  return (
    <div className="fixed right-8 top-1/2 -translate-y-1/2 h-[80vh] w-2 z-[100] pointer-events-none flex flex-col items-center">
      {/* Track */}
      <div className="absolute inset-0 bg-white/5 rounded-full backdrop-blur-sm border border-white/10 w-full" />
      
      {/* Thumb */}
      <div
        ref={thumbRef}
        className={`absolute w-10 h-16 -left-4 rounded-2xl flex items-center justify-center text-2xl transition-transform duration-100 ease-out ${isScrolling ? "electric-glow scale-110" : "scale-100"}`}
        style={{
          top: `${scrollProgress * 85}%`,
          backgroundColor: getThumbColor(),
          boxShadow: `0 0 20px ${getThumbColor()}`,
          transition: "background-color 0.2s ease, top 0.1s linear"
        }}
      >
        <span className="select-none">⚡</span>
        
        {/* Electric Sparks (Optional SVG or CSS Sparks) */}
        {isScrolling && (
          <div className="absolute inset-0 pointer-events-none">
             <div className="absolute -top-2 -left-2 w-4 h-4 bg-white rounded-full blur-xl opacity-50 animate-ping" />
             <div className="absolute -bottom-2 -right-2 w-4 h-4 bg-white rounded-full blur-xl opacity-50 animate-ping delay-75" />
          </div>
        )}
      </div>
    </div>
  );
}
